// Set asterism lines to bright red
var red = core.vec3f(1.0, 0.0, 0.0);
AsterismMgr.setLinesColor(red);

// Set to golden color
var gold = core.vec3f(1.0, 0.84, 0.0);
AsterismMgr.setLinesColor(gold);

// Set to cyan
var cyan = core.vec3f(0.0, 0.8, 0.9);
AsterismMgr.setLinesColor(cyan);

// Save current color to restore later
var savedColor = AsterismMgr.getLinesColor();
AsterismMgr.setLinesColor(savedColor);

var lineColor = AsterismMgr.getLinesColor();
core.debug("Current line color - R: " + lineColor[0] + ", G: " + lineColor[1] + ", B: " + lineColor[2]);

// Store color for later use
var storedColor = AsterismMgr.getLinesColor();

// Check if lines are currently red
if(lineColor[0] > 0.8 && lineColor[1] < 0.2 && lineColor[2] < 0.2) {
    core.debug("Lines are red");
}

// Set ray helpers to light green
var lightGreen = core.vec3f(0.5, 1.0, 0.5);
AsterismMgr.setRayHelpersColor(lightGreen);

// Set to orange
var orange = core.vec3f(1.0, 0.65, 0.0);
AsterismMgr.setRayHelpersColor(orange);

// Set to white for better visibility
var white = core.vec3f(1.0, 1.0, 1.0);
AsterismMgr.setRayHelpersColor(white);

// Set labels to pure white
var white = core.vec3f(1.0, 1.0, 1.0);
AsterismMgr.setLabelsColor(white);

// Set to light yellow for better contrast
var lightYellow = core.vec3f(1.0, 1.0, 0.6);
AsterismMgr.setLabelsColor(lightYellow);

// Set to cyan for a modern look
var cyan = core.vec3f(0.0, 1.0, 1.0);
AsterismMgr.setLabelsColor(cyan);

// Large font for presentations
AsterismMgr.setFontSize(20);

// Default medium size
AsterismMgr.setFontSize(14);

// Small font for minimal interface
AsterismMgr.setFontSize(10);

var currentSize = AsterismMgr.getFontSize();
core.debug("Current font size: " + currentSize + " pixels");

// Thin and elegant lines
AsterismMgr.setAsterismLineThickness(1);

// Default medium thickness
AsterismMgr.setAsterismLineThickness(2);

// Thick lines for presentations
AsterismMgr.setAsterismLineThickness(3);

var thickness = AsterismMgr.getAsterismLineThickness();
core.debug("Line thickness: " + thickness + " px");

// Very thin helpers (subtle)
AsterismMgr.setRayHelperThickness(1);

// More visible helpers
AsterismMgr.setRayHelperThickness(2);

var rayThickness = AsterismMgr.getRayHelperThickness();
core.debug("Ray helper thickness: " + rayThickness);

// Show asterism lines
AsterismMgr.setFlagLines(true);

// Hide asterism lines
AsterismMgr.setFlagLines(false);

// Toggle current state
var current = AsterismMgr.getFlagLines();
AsterismMgr.setFlagLines(!current);

if(AsterismMgr.getFlagLines()) {
    core.debug("Asterism lines are visible");
} else {
    core.debug("Asterism lines are hidden");
    AsterismMgr.setFlagLines(true);
}

// Show asterism labels
AsterismMgr.setFlagLabels(true);

// Show both lines and labels together
AsterismMgr.setFlagLines(true);
AsterismMgr.setFlagLabels(true);

// Hide labels but keep lines
AsterismMgr.setFlagLabels(false);

if(AsterismMgr.getFlagLabels()) {
    core.debug("Asterism labels are visible");
}

// Show ray helpers
AsterismMgr.setFlagRayHelpers(true);

// Hide ray helpers
AsterismMgr.setFlagRayHelpers(false);

// Show main lines with ray helpers
AsterismMgr.setFlagLines(true);
AsterismMgr.setFlagRayHelpers(true);

if(AsterismMgr.getFlagRayHelpers()) {
    core.debug("Ray helpers are visible");
} else {
    core.debug("Ray helpers are hidden");
}

// Fast fade (0.5 seconds)
AsterismMgr.setLinesFadeDuration(0.5);
AsterismMgr.setFlagLines(true);

// Slow dramatic fade (3 seconds)
AsterismMgr.setLinesFadeDuration(3.0);
AsterismMgr.setFlagLines(false);

// Instant change (no fade)
AsterismMgr.setLinesFadeDuration(0);
AsterismMgr.setFlagLines(true);

var fadeDuration = AsterismMgr.getLinesFadeDuration();
core.debug("Line fade duration: " + fadeDuration + " seconds");

// Slow fade for labels
AsterismMgr.setLabelsFadeDuration(2.0);
AsterismMgr.setFlagLabels(true);

// Quick fade
AsterismMgr.setLabelsFadeDuration(0.3);
AsterismMgr.setFlagLabels(false);

var labelFade = AsterismMgr.getLabelsFadeDuration();
core.debug("Label fade duration: " + labelFade);

AsterismMgr.setRayHelpersFadeDuration(1.5);
AsterismMgr.setFlagRayHelpers(true);

var rayFade = AsterismMgr.getRayHelpersFadeDuration();
core.debug("Ray helpers fade duration: " + rayFade);

// Select and display only the Summer Triangle
AsterismMgr.selectAsterism("Summer Triangle");
core.moveToObject("Altair", 2);

// Select the Big Dipper
AsterismMgr.selectAsterism("Big Dipper");

// Select the Northern Cross
AsterismMgr.selectAsterism("Northern Cross");

// Select the Winter Hexagon
AsterismMgr.selectAsterism("Winter Hexagon");

// Select then deselect
AsterismMgr.selectAsterism("Summer Triangle");
core.wait(3);
AsterismMgr.deselectAsterism("Summer Triangle");

// Select multiple then remove one
AsterismMgr.selectAsterism("Big Dipper");
AsterismMgr.selectAsterism("Little Dipper");
AsterismMgr.deselectAsterism("Big Dipper");
// Only 'Little Dipper' remains visible

// Clear all asterism selections
AsterismMgr.deselectAsterisms();

// In a presentation workflow
AsterismMgr.selectAsterism("Summer Triangle");
core.wait(5);
AsterismMgr.deselectAsterisms();
core.debug("Asterism presentation ended");

// Display all asterisms in the current sky culture
AsterismMgr.selectAllAsterisms();

// Change culture then show all
core.setSkyCulture("western");
AsterismMgr.selectAllAsterisms();
core.debug("All western asterisms are now visible");

// Enable isolation mode
AsterismMgr.setFlagIsolateAsterismSelected(true);
AsterismMgr.selectAsterism("Summer Triangle");

// Disable isolation mode (all asterisms become visible)
AsterismMgr.setFlagIsolateAsterismSelected(false);

var isIsolated = AsterismMgr.getFlagIsolateAsterismSelected();
core.debug("Isolation mode active: " + isIsolated);

if(AsterismMgr.getFlagIsolateAsterismSelected()) {
    core.debug("Isolation mode is active - non-selected asterisms are hidden");
} else {
    core.debug("Isolation mode is inactive - all asterisms are visible");
}

// Check before attempting to display asterisms
if(AsterismMgr.isLinesDefined()) {
    core.debug("Current sky culture has asterisms");
    AsterismMgr.setFlagLines(true);
    AsterismMgr.setFlagLabels(true);
} else {
    core.debug("No asterisms in current sky culture");
    core.debug("Switching to western culture...");
    core.setSkyCulture("western");
    core.wait(1);
    if(AsterismMgr.isLinesDefined()) {
        AsterismMgr.setFlagLines(true);
    }
}
